#include <stdio.h>
#include <stdlib.h>
#include <inttypes.h>

typedef struct { long long pos; int delta; } Event;
int cmpEvent(const void *a, const void *b) {
    long long pa = ((Event*)a)->pos;
    long long pb = ((Event*)b)->pos;
    if (pa < pb) return -1;
    if (pa > pb) return 1;
    return ((Event*)a)->delta - ((Event*)b)->delta; // order doesn't matter
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long A,B; scanf("%d %lld %lld", &N, &A, &B);
        __int128 cnt = (__int128)(B - A + 1);
        __int128 sum = (__int128)(A + B) * cnt / 2; // S
        long long S = (long long)sum; // fits in 64 bit
        Event *ev = (Event*)malloc(sizeof(Event) * (2LL*N));
        long long evCnt = 0;
        for(int i=0;i<N;i++){
            long long L,R; scanf("%lld %lld", &L, &R);
            if(R < A || L > S) continue; // no intersection
            long long l = L < A ? A : L;
            long long r = R > S ? S : R;
            ev[evCnt++] = (Event){l, +1};
            if (r != 9223372036854775807LL) // avoid overflow, but r+1 fits in unsigned
                ev[evCnt++] = (Event){r+1, -1};
        }
        qsort(ev, evCnt, sizeof(Event), cmpEvent);
        long long cur = 0, best = 0;
        for(long long i=0;i<evCnt;i++){
            cur += ev[i].delta;
            if(cur > best) best = cur;
        }
        printf("%lld\n", best);
        free(ev);
    }
    return 0;
}

