#include <bits/stdc++.h>
using namespace std;
using int64 = long long;
using i128 = __int128_t;
struct Event{int64 pos; int delta;};
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; int64 A,B; cin>>N>>A>>B;
        i128 cnt = (i128)(B - A + 1);
        i128 sum = (i128)(A + B) * cnt / 2; // S
        int64 S = (int64)sum; // fits in signed 64‑bit
        vector<Event> ev; ev.reserve(2LL*N);
        for(int i=0;i<N;i++){
            int64 L,R; cin>>L>>R;
            if(R < A || L > S) continue;
            int64 l = max(L, A);
            int64 r = min(R, S);
            ev.push_back({l, +1});
            ev.push_back({r+1, -1});
        }
        sort(ev.begin(), ev.end(), [](const Event& a, const Event& b){return a.pos < b.pos;});
        int64 cur=0, best=0;
        for(const auto &e: ev){
            cur += e.delta;
            if(cur>best) best=cur;
        }
        cout<<best<<"\n";
    }
    return 0;
}

