import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) <= ' ') {
                if (c == -1) return Long.MIN_VALUE;
            }
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    static class Event {
        long pos; int delta;
        Event(long p, int d){pos=p; delta=d;}
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        int T = (int)fs.nextLong();
        while (T-- > 0) {
            int N = (int)fs.nextLong();
            long A = fs.nextLong();
            long B = fs.nextLong();
            // compute S = sum_{x=A}^{B} x using BigInteger to avoid overflow
            java.math.BigInteger cnt = java.math.BigInteger.valueOf(B - A + 1);
            java.math.BigInteger sum = java.math.BigInteger.valueOf(A + B).multiply(cnt).divide(java.math.BigInteger.valueOf(2));
            long S = sum.longValue(); // fits into signed 64‑bit for given limits
            List<Event> list = new ArrayList<>(2L * N);
            for (int i = 0; i < N; i++) {
                long L = fs.nextLong();
                long R = fs.nextLong();
                if (R < A || L > S) continue;
                long l = Math.max(L, A);
                long r = Math.min(R, S);
                list.add(new Event(l, 1));
                list.add(new Event(r + 1, -1));
            }
            list.sort(Comparator.comparingLong(e -> e.pos));
            long cur = 0, best = 0;
            for (Event e : list) {
                cur += e.delta;
                if (cur > best) best = cur;
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }
}

