const fs = require('fs');
const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/).map(BigInt);
let idx = 0n;
function next(){return data[idx++];}
const T = Number(next());
let out = [];
for(let tc=0; tc<T; ++tc){
  const N = Number(next());
  const A = next();
  const B = next();
  const S = (A + B) * (B - A + 1n) / 2n; // total sum
  let events = [];
  for(let i=0;i<N;i++){
    const L = next();
    const R = next();
    if(R < A || L > S) continue;
    const l = L > A ? L : A;
    const r = R < S ? R : S;
    events.push([l, 1]);
    events.push([r + 1n, -1]);
  }
  events.sort((a,b)=> (a[0] < b[0] ? -1 : a[0] > b[0] ? 1 : a[1]-b[1]));
  let cur = 0n, best = 0n;
  for(const e of events){
    cur += BigInt(e[1]);
    if(cur > best) best = cur;
  }
  out.push(best.toString());
}
console.log(out.join('\n'));

